SELECT
,

FROM yx_classroom_application a
LEFT JOIN yx_user u ON a.applicant_id = u.id AND u.is_deleted = FALSE
LEFT JOIN yx_classroom c ON a.classroom_id = c.id AND c.is_deleted = FALSE
WHERE a.is_deleted = FALSE

    AND a.applicant_id = #{applicantId}


    AND a.classroom_id = #{classroomId}


    AND a.status = #{status}

ORDER BY a.created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM yx_classroom_application a
WHERE a.is_deleted = FALSE

    AND a.applicant_id = #{applicantId}


    AND a.classroom_id = #{classroomId}


    AND a.status = #{status}

